import { useEffect, useMemo, useState } from "react";
import {
  createInvoice,
  downloadInvoicePdf,
  getCustomers,
  getInvoices,
  getProducts,
} from "../services/api";
import "../css/Billing.css";

function Billing() {
  const [customers, setCustomers] = useState([]);
  const [products, setProducts] = useState([]);
  const [formData, setFormData] = useState({
    customerId: "",
    productId: "",
    quantity: 1,
  });
  const [cart, setCart] = useState([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState("");
  const [messageType, setMessageType] = useState("");
  const [createdInvoice, setCreatedInvoice] = useState(null);
  const [createdReceipt, setCreatedReceipt] = useState(null);
  const [invoiceDateFilter, setInvoiceDateFilter] = useState("");
  const [invoiceHistory, setInvoiceHistory] = useState([]);

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [customersRes, productsRes, invoicesRes] = await Promise.all([
          getCustomers(),
          getProducts(),
          getInvoices(""),
        ]);
        setCustomers(customersRes.data || []);
        setProducts(productsRes.data || []);
        setInvoiceHistory(invoicesRes.data || []);
      } catch (error) {
        setCustomers([]);
        setProducts([]);
        setInvoiceHistory([]);
      }
    };

    loadInitialData();
  }, []);

  useEffect(() => {
    const loadInvoices = async () => {
      try {
        const response = await getInvoices(invoiceDateFilter);
        setInvoiceHistory(response.data || []);
      } catch (error) {
        setInvoiceHistory([]);
      }
    };
    loadInvoices();
  }, [invoiceDateFilter]);

  const handleChange = (event) => {
    const { name, value } = event.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const addToCart = () => {
    if (!formData.productId || Number(formData.quantity) <= 0) {
      return;
    }

    const product = products.find((item) => item._id === formData.productId);
    if (!product) {
      return;
    }

    const quantity = Number(formData.quantity);
    const existing = cart.find((item) => item.productId === formData.productId);

    if (existing) {
      setCart((prev) =>
        prev.map((item) =>
          item.productId === formData.productId ? { ...item, quantity: item.quantity + quantity } : item
        )
      );
    } else {
      setCart((prev) => [
        ...prev,
        {
          productId: product._id,
          name: product.name,
          price: product.price,
          quantity,
        },
      ]);
    }
  };

  const updateQuantity = (productId, qty) => {
    const quantity = Number(qty);
    if (Number.isNaN(quantity) || quantity <= 0) {
      return;
    }

    setCart((prev) => prev.map((item) => (item.productId === productId ? { ...item, quantity } : item)));
  };

  const removeCartItem = (productId) => {
    setCart((prev) => prev.filter((item) => item.productId !== productId));
  };

  const totalAmount = useMemo(
    () => cart.reduce((sum, item) => sum + Number(item.price) * Number(item.quantity), 0),
    [cart]
  );

  const handleSubmit = async (event) => {
    event.preventDefault();
    setMessage("");
    setCreatedInvoice(null);
    setCreatedReceipt(null);

    if (!formData.customerId || cart.length === 0) {
      setMessageType("danger");
      setMessage("Please select customer and add at least one product.");
      return;
    }

    try {
      setIsSubmitting(true);
      const response = await createInvoice({
        customerId: formData.customerId,
        items: cart.map((item) => ({
          productId: item.productId,
          quantity: Number(item.quantity),
        })),
      });

      setMessageType("success");
      setMessage("Invoice created and payment approved.");
      setFormData((prev) => ({
        ...prev,
        productId: "",
        quantity: 1,
      }));
      setCart([]);
      setCreatedInvoice(response.data.invoice);
      setCreatedReceipt(response.data.receipt);
      const [productsRes, invoicesRes] = await Promise.all([
        getProducts(),
        getInvoices(invoiceDateFilter),
      ]);
      setProducts(productsRes.data || []);
      setInvoiceHistory(invoicesRes.data || []);
    } catch (error) {
      setMessageType("danger");
      setMessage(error.response?.data?.message || "Failed to create invoice.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDownloadInvoice = async () => {
    if (!createdInvoice) {
      return;
    }
    const response = await downloadInvoicePdf(createdInvoice._id);
    const url = URL.createObjectURL(new Blob([response.data], { type: "application/pdf" }));
    const link = document.createElement("a");
    link.href = url;
    link.download = `invoice-${createdInvoice.invoiceNumber}.pdf`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <section className="billing-page">
      <div className="container-fluid">
        <section className="billing-header mb-4">
          <h2 className="billing-title">Billing / Invoice</h2>
          <p className="billing-subtitle">Create customer invoice and auto-update product stock.</p>
        </section>

        <section className="billing-card card border-0 shadow-sm">
          <div className="card-body p-4">
            {message && <div className={`alert alert-${messageType}`}>{message}</div>}

            <form onSubmit={handleSubmit}>
              <div className="row g-3">
                <div className="col-md-6">
                  <label htmlFor="customerId" className="form-label">
                    Customer
                  </label>
                  <select
                    id="customerId"
                    name="customerId"
                    className="form-select"
                    value={formData.customerId}
                    onChange={handleChange}
                    required
                  >
                    <option value="">Choose customer</option>
                    {customers.map((customer) => (
                      <option key={customer._id} value={customer._id}>
                        {customer.name} ({customer.phone})
                      </option>
                    ))}
                  </select>
                </div>

                <div className="col-md-3">
                  <label htmlFor="productId" className="form-label">
                    Product
                  </label>
                  <select
                    id="productId"
                    name="productId"
                    className="form-select"
                    value={formData.productId}
                    onChange={handleChange}
                  >
                    <option value="">Choose product</option>
                    {products.map((product) => (
                      <option key={product._id} value={product._id}>
                        {product.name} (Stock: {product.stockQuantity})
                      </option>
                    ))}
                  </select>
                </div>

                <div className="col-md-3">
                  <label htmlFor="quantity" className="form-label">
                    Quantity
                  </label>
                  <input
                    id="quantity"
                    type="number"
                    min="1"
                    name="quantity"
                    className="form-control"
                    value={formData.quantity}
                    onChange={handleChange}
                    placeholder="Qty"
                  />
                </div>

                <div className="col-12">
                  <button type="button" className="btn btn-outline-primary add-item-btn" onClick={addToCart}>
                    Add Item To Cart
                  </button>
                </div>
              </div>

              <div className="table-responsive billing-cart-table-wrap">
                <table className="table align-middle billing-cart-table">
                  <thead>
                    <tr>
                      <th>Product</th>
                      <th>Price</th>
                      <th>Quantity</th>
                      <th>Total</th>
                      <th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {cart.length ? (
                      cart.map((item) => (
                        <tr key={item.productId}>
                          <td>{item.name}</td>
                          <td>Rs {Number(item.price).toLocaleString("en-IN")}</td>
                          <td>
                            <input
                              type="number"
                              min="1"
                              className="form-control cart-qty-input"
                              value={item.quantity}
                              onChange={(event) => updateQuantity(item.productId, event.target.value)}
                            />
                          </td>
                          <td>Rs {(Number(item.price) * Number(item.quantity)).toLocaleString("en-IN")}</td>
                          <td>
                            <button
                              type="button"
                              className="btn btn-sm btn-outline-danger"
                              onClick={() => removeCartItem(item.productId)}
                            >
                              Remove
                            </button>
                          </td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan="5" className="text-center py-3">
                          No products in cart.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>

              <div className="billing-total-wrap">
                <span className="billing-total-label">Total Amount:</span>
                <span className="billing-total-value">Rs {totalAmount.toLocaleString("en-IN")}</span>
              </div>

              <div className="mt-4">
                <button type="submit" className="btn submit-btn" disabled={isSubmitting}>
                  {isSubmitting ? "Processing..." : "Create Invoice"}
                </button>
              </div>
            </form>
          </div>
        </section>

        <section className="billing-result-card card border-0 shadow-sm mt-4">
          <div className="card-body p-4">
            <h5 className="billing-result-title">Latest Invoice</h5>
            {createdInvoice ? (
              <div className="billing-result-content">
                <p className="mb-1">Invoice: {createdInvoice.invoiceNumber}</p>
                <p className="mb-1">Receipt: {createdReceipt?.receiptNumber}</p>
                <p className="mb-3">Amount: Rs {Number(createdInvoice.totalAmount).toLocaleString("en-IN")}</p>
                <button type="button" className="btn btn-primary" onClick={handleDownloadInvoice}>
                  Download Invoice PDF
                </button>
              </div>
            ) : (
              <p className="billing-result-empty">Create an invoice to view the result here.</p>
            )}
      </div>
    </section>

        <section className="billing-history-card card border-0 shadow-sm mt-4">
          <div className="card-body p-4">
            <div className="row g-3 align-items-end mb-3">
              <div className="col-md-4">
                <h5 className="billing-history-title mb-1">Invoice History</h5>
                <p className="billing-history-subtitle mb-0">
                  Filter invoices by date and download PDF.
                </p>
              </div>
              <div className="col-md-3 ms-auto">
                <label htmlFor="invoiceDate" className="form-label">
                  Filter By Date
                </label>
                <input
                  id="invoiceDate"
                  type="date"
                  className="form-control"
                  value={invoiceDateFilter}
                  onChange={(event) => setInvoiceDateFilter(event.target.value)}
                />
              </div>
            </div>

            <div className="table-responsive">
              <table className="table align-middle billing-history-table mb-0">
                <thead>
                  <tr>
                    <th>Invoice ID</th>
                    <th>Customer</th>
                    <th>Amount</th>
                    <th>Date</th>
                    <th>Download</th>
                  </tr>
                </thead>
                <tbody>
                  {invoiceHistory.length ? (
                    invoiceHistory.map((invoice) => (
                      <tr key={invoice._id}>
                        <td>{invoice.invoiceNumber}</td>
                        <td>{invoice.customerId?.name || "N/A"}</td>
                        <td>Rs {Number(invoice.totalAmount).toLocaleString("en-IN")}</td>
                        <td>{new Date(invoice.createdAt).toLocaleDateString("en-IN")}</td>
                        <td>
                          <button
                            type="button"
                            className="btn btn-sm btn-outline-primary"
                            onClick={async () => {
                              const res = await downloadInvoicePdf(invoice._id);
                              const url = URL.createObjectURL(
                                new Blob([res.data], { type: "application/pdf" })
                              );
                              const link = document.createElement("a");
                              link.href = url;
                              link.download = `invoice-${invoice.invoiceNumber}.pdf`;
                              link.click();
                              URL.revokeObjectURL(url);
                            }}
                          >
                            PDF
                          </button>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan="5" className="text-center py-3">
                        No invoices found.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </section>
      </div>
    </section>
  );
}

export default Billing;
